@startuml
title BADEXAMPLE's Class Diagram

package "solid" {
  package "liskov" {
    package "badexample" {
      class Rectangle {
        -height : int
        -width : int
        +area()
        +getHeight()
        +getWidth()
        +setHeight()
        +setWidth()
      }

      class Square {
        +setHeight()
        +setWidth()
      }

      class RectangleTest {
        +areaShouldBeCalculatedCorrectlyWithDerivedClassSquare()
        +areaShouldBeCalculatedCorrectlyWithRectangle()
      }

      Square --|> Rectangle
    }
  }
}

@enduml
